        await page.goto(routeUrl(control.sourcePageRoute || CONTRACT.pages[0].route), { waitUntil: 'networkidle' });
        const input = page.locator(control.selector).first();
        await input.waitFor({ state: 'visible', timeout: 3000 });
        const htmlType = String(control.action.htmlType || '').toLowerCase();
        if (htmlType === 'select') {
          const choices = Array.isArray(control.action.choices) ? control.action.choices : [];
          if (choices.length > 0) {
            const choice = choices.length > 1 ? choices[1] : choices[0];
            await input.selectOption({ label: String(choice) }).catch(async () => {
              await input.selectOption(String(choice));
            });
            const value = await input.inputValue().catch(() => '');
            assert(String(value).length > 0, 'Select "' + control.label + '" should accept a choice.');
          }
        } else if (htmlType === 'checkbox') {
          const before = await input.isChecked();
          await input.setChecked(!before);
          const after = await input.isChecked();
          assert(after !== before, 'Input "' + control.label + '" should toggle checked state.');
        } else if (htmlType === 'file') {
          const disabled = await input.isDisabled().catch(() => false);
          assert(!disabled, 'File input "' + control.label + '" should be usable.');
        } else if (htmlType === 'rich-text') {
          await input.evaluate((el) => {
            el.textContent = 'UAT sample text';
            el.dispatchEvent(new InputEvent('input', { bubbles: true, inputType: 'insertText', data: 'UAT sample text' }));
          });
        } else {
          await input.fill(htmlType === 'number' ? '42' : 'UAT sample text');
          const value = await input.inputValue().catch(() => '');
          assert(String(value).length > 0, 'Input "' + control.label + '" should accept a value.');
        }
